class CookieConsent{constructor(options={}){this.defaults={cookieName:"cookie_consent_accepted",cookieExpiry:365,showDelay:2e3,containerClass:"cookies",btnClass:".cookies__btn",activeClass:"active",debug:false};this.config={...this.defaults,...options};this.onAccept=options.onAccept||null;this.container=null;this.acceptBtn=null;this.isVisible=false;this.consentGiven=false;this.handleAccept=this.handleAccept.bind(this);this.init()}init(){this.consentGiven=this.getCookie(this.config.cookieName)==="true";if(!this.consentGiven){this.setupDOM();this.setupEventListeners();this.showWithDelay()}this.log("CookieConsent инициализирован")}setupDOM(){this.container=document.querySelector(`.${this.config.containerClass}`);if(!this.container){console.warn(`Cookie контейнер с классом "${this.config.containerClass}" не найден`);return false}this.acceptBtn=this.container.querySelector(this.config.btnClass);return true}setupEventListeners(){if(this.acceptBtn){this.acceptBtn.addEventListener("click",this.handleAccept)}}showWithDelay(){if(!this.container||this.consentGiven)return;setTimeout(()=>{this.show()},this.config.showDelay)}show(){if(!this.container||this.isVisible)return;this.container.classList.add(this.config.activeClass);this.isVisible=true;this.log("Cookie баннер показан")}hide(){if(!this.container||!this.isVisible)return;this.container.classList.remove(this.config.activeClass);this.isVisible=false;this.log("Cookie баннер скрыт")}handleAccept(){this.setCookie(this.config.cookieName,"true",this.config.cookieExpiry);this.consentGiven=true;this.hide();this.log("Согласие на куки принято");if(this.onAccept){this.onAccept()}document.dispatchEvent(new CustomEvent("cookieConsentAccepted"))}setCookie(name,value,days){const date=new Date;date.setTime(date.getTime()+days*24*60*60*1e3);let cookie=`${encodeURIComponent(name)}=${encodeURIComponent(value)};expires=${date.toUTCString()};path=/;SameSite=Lax`;if(window.location.protocol==="https:"){cookie+=";Secure"}document.cookie=cookie}getCookie(name){const cookieName=name+"=";let decodedCookie;try{decodedCookie=decodeURIComponent(document.cookie)}catch(e){return null}const cookieArray=decodedCookie.split(";");for(let i=0;i<cookieArray.length;i++){let cookie=cookieArray[i];while(cookie.charAt(0)===" "){cookie=cookie.substring(1)}if(cookie.indexOf(cookieName)===0){return cookie.substring(cookieName.length,cookie.length)}}return null}removeCookie(name){this.setCookie(name,"",-1)}hasConsent(){return this.consentGiven}reset(){this.removeCookie(this.config.cookieName);this.consentGiven=false;this.isVisible=false;if(this.container){this.container.classList.remove(this.config.activeClass)}this.log("Согласие сброшено")}log(message){if(this.config.debug){console.log(`[CookieConsent] ${message}`)}}destroy(){if(this.acceptBtn){this.acceptBtn.removeEventListener("click",this.handleAccept)}this.log("CookieConsent уничтожен")}}